//-------------------------------------------------------------------------
// scwin.name : f_Retrieve
// scwin.desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
	//ds_cndLine.UseChangeInfo = "false";
	//if(ds_line.IsUpdated){ //수정된 내용이 있는지 체크

    ds_line.setJSON([]);
    if(ds_line.getModifiedJSON().length > 0 && scwin.updateYn == "N"){ //수정된 내용이 있는지 체크
		if( await $c.win.confirm(MSG_CM_CRM_005) ){ 
			scwin.retrieveYn = "Y";
            $c.sbm.execute(sbm_retrieve);

		    //tr_retrieve.Action = "/ds.lo.comninfomgnt.RetrieveLineListCMD.do";
		    //tr_retrieve.Post();
    	}
    }else{			
	    scwin.retrieveYn = "Y";
        $c.sbm.execute(sbm_retrieve);

	    //tr_retrieve.Action = "/ds.lo.comninfomgnt.RetrieveLineListCMD.do";
	    //tr_retrieve.Post();
    }
};

//-------------------------------------------------------------------------
// scwin.name : f_Save
// scwin.desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
	//if(ds_line.IsUpdated){
console.log('f_Save~~');
    if(ds_line.getModifiedJSON().length > 0){ //수정된 내용이 있는지 체크
		//if(await $c.gus.cfValidateGrid(gr_line)){
console.log('cfValidateGrid~~');

            if(!await scwin.gridValidateChk()) return;
			if(!await scwin.f_validate()) return;


			if(await $c.win.confirm(MSG_CM_CRM_001)){ //저장하시겠습니까?	
				scwin.pos_line = ds_line.getRowPosition();			
                $c.sbm.execute(sbm_save);

				//tr_save.Action = "/ds.lo.comninfomgnt.SaveLineListCMD.do";
		    	//tr_save.Post();
	    	}
		//}	
	}else{
		await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["Line관리"]); //@은(는) 변경된 사항이 없습니다
	}
};

scwin.gridValidateChk = async function(){
    let validArry = [
        {id:"adptDt", name: "적용일자", mandatory:true, valid:"date", format:"YYYYMMDD"}
        ,{id:"lineCd", name: "LINE코드", mandatory:true}
        ,{id:"lineNm", name: "LINE코드명", mandatory:true}
        ,{id:"lineClsCd", name: "라인구분", mandatory:true}
        ,{id:"shpCoMark", name: "선사부호", maxLength:4}
        ,{id:"lineClntNo", name: "라인거래처코드", maxLength:6}
        ,{id:"lineClntNm", name: "라인거래처명", byteLength:30}
        ,{id:"shpCoClntNo", name: "선사거래처코드", maxLength:6}
        ,{id:"shpCoClntNm", name: "선사거래처명", byteLength:30}
    ];

    let gridName = "라인코드";
    if(!await $c.gus.cfValidateGrid(gr_line, null, null, validArry, gridName)){
        return false;
    }

    //중복체크
    var errCnt = 0;
    for(var i=0;i< ds_line.getRowCount();i++){
        for(var j=0;j< ds_line.getRowCount();j++){
            if(i!=j && ds_line.getCellData(i,'lineCd') == ds_line.getCellData(j,'lineCd')
                    && ds_line.getCellData(i,'shpCoMark') == ds_line.getCellData(j,'shpCoMark'))
            {
                errCnt = j+1;
                break;
            }
        }
        if(errCnt > 0){
            await $c.win.alert("라인코드의 "+errCnt+"번째 데이터에서 LINE코드, 선사부호은(는) 중복될 수 없습니다.");
            return false;
        }
    }

	return true;
};

//-------------------------------------------------------------------------
// scwin.name : f_addRow
// scwin.desc : 행추가
//-------------------------------------------------------------------------
scwin.f_addRow = function () {
	//if(ds_line.getRowCount() == 0)	scwin.f_setDSHeader("2", ds_line);	

	var row = ds_line.insertRow();
	ds_line.setCellData(row, "lineClsCd",DsConstants.LINE_CLS_CD_CTRT);
	ds_line.setCellData(row, "useYn",1);

    gr_line.setFocusedCell(row, "adptDt", true);

	//gr_line.SetColumn("adptDt");
	$c.gus.cfEnableBtnOnly([btn_save]);
};

