scwin.sbm_retrieve_submitdone = async function (e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) {
            //cfShowError(tr_retrieve);
	        scwin.retrieveYn = "N";
            return;
        } //onFail

        var rowcnt = ds_line.getRowCount();
        tbx_totalRows.setValue(rowcnt);

        if (rowcnt == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
            return;
        }

        //$c.gus.cfGoPrevPosition(gr_line, scwin.pos_line);
        scwin.retrieveYn = "N";
        scwin.updateYn = "N";
        gr_line.setFocusedCell(0, "adptDt", false);
    } catch (e) {
       console.log("sbm_retrieve_submitdone : " + e);
    }
};

scwin.sbm_retrieve_submiterror = function (e) {
    //cfShowError(tr_retrieve);
	scwin.retrieveYn	= "N";
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다

    scwin.updateYn = "Y";
	scwin.f_Retrieve();
};

