            gr_line.setReadOnly("cell", row, "adptDt", false);
            gr_line.setReadOnly("cell", row, "lineCd", false);
			//gr_line.ColumnProp("adptDt","Edit")="Numeric";
			//gr_line.ColumnProp("lineCd","Edit")="AlphaUpper";
